import{_ as t,o as s,c as i,a2 as o}from"./chunks/framework.il0noOp3.js";const u=JSON.parse('{"title":"Assessment Auth & Permissions","description":"The minimum RBAC and Microsoft Graph permissions each AzureScout assessment needs, and how to pre-flight them with -PermissionAudit.","frontmatter":{"description":"The minimum RBAC and Microsoft Graph permissions each AzureScout assessment needs, and how to pre-flight them with -PermissionAudit."},"headers":[],"relativePath":"assessment-permissions.md","filePath":"assessment-permissions.md"}'),a={name:"assessment-permissions.md"};function n(d,e,r,c,l,h){return s(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="assessment-auth-permissions" tabindex="-1">Assessment Auth &amp; Permissions <a class="header-anchor" href="#assessment-auth-permissions" aria-label="Permalink to &quot;Assessment Auth &amp; Permissions&quot;">​</a></h1><p>This page is specific to the CAF/WAF assessment platform (<code>Invoke-ScoutAssessment</code>). It is a <strong>different, narrower permission model</strong> than the v1 inventory cmdlet&#39;s — see <a href="./permissions.html">Permissions</a> for the <code>Invoke-AzureScout</code> / <code>Test-AZSCPermissions</code> model, which is not the same function and is not what this page describes.</p><p>Source of truth: <code>src/assess/Test-ScoutPermission.ps1</code>, <code>src/ingest/Import-Governance.ps1</code> (the default governance collector), and <code>src/ingest/Import-AzGovViz.ps1</code> (the opt-in third-party collector).</p><div class="info custom-block"><p class="custom-block-title">Governance data is native by default — no Graph permission required for it</p><p>As of the native governance collector (AB#5041), the five assessments whose <code>Ingest</code> used to be <code>AzGovViz</code> (<code>LandingZone</code>, <code>Management</code>, <code>Identity</code>, <code>Governance</code>, <code>Policy</code>) now use <code>Ingest = Governance</code> by default — <code>Import-Governance</code> populates <code>collect.json</code>&#39;s <code>governance</code> object from Azure Resource Graph and ambient-token ARM REST calls, needing <strong>only ARM Reader at the management-group root</strong>, the same requirement every other assessment already has. The Microsoft Graph application permissions below are needed <strong>only if you explicitly opt an assessment into the legacy <code>AzGovViz</code> ingestor value</strong> instead of the native default — they are no longer a default requirement for any assessment.</p></div><h2 id="the-short-version" tabindex="-1">The short version <a class="header-anchor" href="#the-short-version" aria-label="Permalink to &quot;The short version&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Who needs it</th></tr></thead><tbody><tr><td><strong>ARM <code>Reader</code> at the tenant-root management group</strong></td><td><strong>Every assessment, with no exception</strong> — including the 5 governance-data assessments, now served by the native <code>Import-Governance</code> collector.</td></tr><tr><td><strong>Microsoft Graph app permissions</strong> (<code>User.Read.All</code>, <code>Group.Read.All</code>, <code>Application.Read.All</code>, <code>PrivilegedAccess.Read.AzureResources</code>)</td><td><strong>Only</strong> if you opt an assessment into the legacy <code>AzGovViz</code> ingestor instead of the native <code>Governance</code> default. Not required by any assessment out of the box.</td></tr></tbody></table><p>All 22 assessments in <a href="./design/assessment-registry.html">the registry</a> need <strong>ARM Reader only</strong> by default. No Graph permission, delegated or application, is required unless you deliberately switch an assessment&#39;s <code>Ingest</code> back to <code>AzGovViz</code>.</p><div class="tip custom-block"><p class="custom-block-title">Check before you scan</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Identity </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PermissionAudit</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Runs <code>Test-ScoutPermission</code> for the given assessment(s) and returns/prints a table before any collection happens. See <a href="#what-permissionaudit-actually-verifies">what it actually checks</a> below — it is not a full live Graph check.</p></div><h2 id="why-arm-reader-must-be-at-the-management-group-root-not-the-subscription" tabindex="-1">Why ARM Reader must be at the management-group root, not the subscription <a class="header-anchor" href="#why-arm-reader-must-be-at-the-management-group-root-not-the-subscription" aria-label="Permalink to &quot;Why ARM Reader must be at the management-group root, not the subscription&quot;">​</a></h2><p><code>Test-ScoutPermission</code> checks the role assignment at <code>/providers/Microsoft.Management/managementGroups/&lt;tenantId&gt;</code> — i.e. the <strong>tenant root management group</strong>, not any individual subscription:</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-AzRoleAssignment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Scope </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/providers/Microsoft.Management/managementGroups/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ctx.Tenant.Id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> `</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SignInName $ctx.Account.Id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Where-Object</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> RoleDefinitionName </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-eq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Reader&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>A <code>Reader</code> assignment scoped only to individual subscriptions will <strong>fail</strong> this specific check (<code>Test-ScoutPermission</code> does not walk down to subscription-level assignments as a fallback). Assign <code>Reader</code> at the root management group so every subscription under it inherits read access.</p><h2 id="per-assessment-matrix" tabindex="-1">Per-assessment matrix <a class="header-anchor" href="#per-assessment-matrix" aria-label="Permalink to &quot;Per-assessment matrix&quot;">​</a></h2><p>&quot;Governance data&quot; marks the 5 assessments that collect governance data — <strong>by default</strong> via the native <code>Import-Governance</code> collector (ARM Reader only, same as every other row). &quot;Graph (opt-in <code>AzGovViz</code>)&quot; is only <strong>Yes</strong> if you&#39;ve explicitly switched that assessment&#39;s <code>Ingest</code> back to the legacy <code>AzGovViz</code> value — none of them require Graph out of the box.</p><table tabindex="0"><thead><tr><th>Assessment</th><th>ARM Reader @ MG root</th><th>Governance data</th><th>Graph (opt-in <code>AzGovViz</code>)</th></tr></thead><tbody><tr><td><code>LandingZone</code></td><td>Required</td><td><strong>Yes</strong> (native)</td><td>Only if opted in</td></tr><tr><td><code>Estate</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Management</code></td><td>Required</td><td><strong>Yes</strong> (native)</td><td>Only if opted in</td></tr><tr><td><code>Monitor</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Networking</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Identity</code></td><td>Required</td><td><strong>Yes</strong> (native)</td><td>Only if opted in</td></tr><tr><td><code>Security</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Compute</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Storage</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Databases</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Containers</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Web</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Analytics</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>AI</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Integration</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Hybrid</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>IoT</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Governance</code></td><td>Required</td><td><strong>Yes</strong> (native)</td><td>Only if opted in</td></tr><tr><td><code>Policy</code></td><td>Required</td><td><strong>Yes</strong> (native)</td><td>Only if opted in</td></tr><tr><td><code>UpdateManager</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Monitoring</code></td><td>Required</td><td>No</td><td>No</td></tr><tr><td><code>Cost</code></td><td>Required</td><td>No</td><td>No</td></tr></tbody></table><h2 id="the-graph-permissions-only-if-you-opt-into-the-legacy-azgovviz-ingestor" tabindex="-1">The Graph permissions (only if you opt into the legacy <code>AzGovViz</code> ingestor) <a class="header-anchor" href="#the-graph-permissions-only-if-you-opt-into-the-legacy-azgovviz-ingestor" aria-label="Permalink to &quot;The Graph permissions (only if you opt into the legacy `AzGovViz` ingestor)&quot;">​</a></h2><p>These four application permissions are <strong>not needed by default for any assessment</strong> — the native <code>Import-Governance</code> collector needs only ARM Reader. They only apply if you explicitly set an assessment&#39;s <code>Ingest</code> back to <code>AzGovViz</code>. When <code>Test-ScoutPermission</code> sees an <code>AzGovViz</code>-ingesting assessment in the requested set, it lists these four application permissions:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>User.Read.All</code></td><td>AzGovViz&#39;s identity export</td></tr><tr><td><code>Group.Read.All</code></td><td>AzGovViz&#39;s identity export</td></tr><tr><td><code>Application.Read.All</code></td><td>AzGovViz&#39;s identity export</td></tr><tr><td><code>PrivilegedAccess.Read.AzureResources</code></td><td>PIM-eligible role assignments — <strong>requires an Entra ID P2 license</strong></td></tr></tbody></table><p>Grant these as <strong>application permissions with admin consent</strong> on the service principal / app registration AzureScout authenticates as (or a user account in <strong>Directory Readers</strong>, per <code>Test-ScoutPermission</code>&#39;s remediation text).</p><div class="warning custom-block"><p class="custom-block-title"><code>PrivilegedAccess.Read.AzureResources</code> is currently never exercised</p><p><code>Import-AzGovViz.ps1</code> <strong>always</strong> passes <code>-NoPIMEligibility</code> to the Azure Governance Visualizer — unconditionally, not only when the permission/license is missing:</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$govPath</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/repo/pwsh/AzGovVizParallel.ps1&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> `</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ManagementGroupId $ManagementGroupId </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">`</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputPath        $govPath </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">`</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DoPSRule </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">`</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NoScopeInsights </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">`</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NoPIMEligibility </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">`</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ALZPolicyAssignmentsChecker</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>In the current implementation, PIM-eligibility data is <strong>never</strong> collected through this ingest path, regardless of whether you grant <code>PrivilegedAccess.Read.AzureResources</code> or hold an Entra ID P2 license. The permission is still listed by <code>Test-ScoutPermission</code> (it&#39;s part of AzGovViz&#39;s own general permission set) — grant it if you want to future-proof for when <code>-NoPIMEligibility</code> is lifted, but do not expect PIM data in <code>findings.json</code> today. This is a real gap between the permission checklist and what the code does; flagged here rather than silently documented as &quot;working.&quot;</p></div><h2 id="what-permissionaudit-actually-verifies" tabindex="-1">What <code>-PermissionAudit</code> actually verifies <a class="header-anchor" href="#what-permissionaudit-actually-verifies" aria-label="Permalink to &quot;What `-PermissionAudit` actually verifies&quot;">​</a></h2><p><code>Test-ScoutPermission</code> performs <strong>one live check and one static checklist</strong> — they are not the same kind of validation:</p><table tabindex="0"><thead><tr><th>Check</th><th>How it&#39;s validated</th><th><code>Ok</code> value</th></tr></thead><tbody><tr><td><code>ARM Reader @ MG root</code></td><td><strong>Live</strong> — actually calls <code>Get-AzRoleAssignment</code> against the current context</td><td><code>$true</code> / <code>$false</code></td></tr><tr><td><code>Graph: &lt;permission&gt;</code> (×4, only when an assessment is explicitly opted into the legacy <code>AzGovViz</code> ingestor)</td><td><strong>Not validated</strong> — always emitted with <code>Ok = $null</code> as an informational checklist entry</td><td><code>$null</code> (always)</td></tr></tbody></table><p>In other words: <code>-PermissionAudit</code> will tell you definitively whether your ARM Reader assignment is correct, but it does <strong>not</strong> call Microsoft Graph to confirm the four app permissions are actually granted — it only reminds you they&#39;re needed and what to do about it (<code>Fix</code> column). Verify Graph application permissions independently (Entra admin center → App registrations → API permissions, or <code>Get-MgServicePrincipalAppRoleAssignment</code>) before relying on a clean <code>-PermissionAudit</code> run as proof they&#39;re in place.</p><h2 id="managementgroupid-and-governance-data-collection" tabindex="-1"><code>-ManagementGroupId</code> and governance data collection <a class="header-anchor" href="#managementgroupid-and-governance-data-collection" aria-label="Permalink to &quot;`-ManagementGroupId` and governance data collection&quot;">​</a></h2><p>By default, the 5 governance-data assessments (<code>LandingZone</code>, <code>Management</code>, <code>Identity</code>, <code>Governance</code>, <code>Policy</code>) use the native <code>Import-Governance</code> collector, which does <strong>not</strong> need an explicit <code>-ManagementGroupId</code> to run — it collects via Azure Resource Graph and ambient-token ARM REST calls regardless. What actually depends on management-group visibility is the <strong>ALZ benchmark diff</strong>: if the identity running the scan doesn&#39;t have Reader at the management-group root, the benchmark degrades to an explicit <code>Unknown</code> (with remediation guidance pointing at &quot;grant Reader at MG root&quot;) rather than a false 0%. This is not a permission failure and will not show up in <code>-PermissionAudit</code>.</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ManagementGroupId </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;contoso-root-mg&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>-ManagementGroupId</code> scopes the Resource Graph <code>Collect</code> layer — <code>Invoke-Collect</code> and <code>Invoke-ArgQueryPack</code> pass it through to every <code>Search-AzGraph</code> call as <code>-ManagementGroup</code>. Omitting it leaves ARG queries running tenant-wide against whatever your authenticated context can see (no <code>-ManagementGroup</code>/<code>-Subscription</code> filter is sent at all). The ARM <code>Reader</code> requirement in <a href="#the-short-version">The short version</a> still applies regardless of whether you pass <code>-ManagementGroupId</code> — it only narrows <em>which</em> subscriptions under your Reader scope get queried, it does not substitute for the role assignment.</p><p>If you&#39;ve opted an assessment into the legacy <code>AzGovViz</code> ingestor instead of the native default, <code>Import-AzGovViz.ps1</code> still needs an explicit <code>-ManagementGroupId</code> to know where to scope the Azure Governance Visualizer run — omitting it there logs <code>Import-AzGovViz: no -ManagementGroupId supplied; skipping AzGovViz ingest</code> and that ingestor&#39;s data is skipped, same behavior as before this default changed.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="./assessment.html">Assessment guide — run modes and examples</a></li><li><a href="./design/assessment-registry.html">Assessment Registry — all 22 assessments</a></li><li><a href="./assessment-prerequisites.html">Assessment prerequisites</a></li><li>v1 inventory&#39;s separate model: <a href="./permissions.html">Permissions</a>, <a href="./authentication.html">Authentication</a></li></ul>',31)])])}const g=t(a,[["render",n]]);export{u as __pageData,g as default};
